export const 召雷飛符三 = (bi) => {
    const u = bi.u, k = 1.5;
    const X = (c) => (c - 8.8) * k;
    const Z = (r) => (r - 4.2) * k + 3;
    const 抖 = (書, 寬 = 0.72) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    bi.硃(() => {
        // 左：丶挑入波鏈（斷筆二段，波幅足）
        抖(p => p.M(X(3.4), Z(4.2))
            .C(X(4.3), Z(4.6), X(4.9), Z(5.3), X(4.7), Z(6.1))
            .C(X(4.6), Z(6.9), X(5.6), Z(7.2), X(6.3), Z(7.9))
            .C(X(6.7), Z(8.3), X(6.6), Z(8.7), X(6.2), Z(8.9)), 0.7);
        抖(p => p.M(X(6.7), Z(9.4))
            .C(X(7.3), Z(9.9), X(7.6), Z(10.4), X(7.5), Z(11.0)), 0.66);
        // 大蛇曲（三折切返幅張貫底）
        抖(p => p.M(X(7.5), Z(11.2))
            .C(X(7.4), Z(12.2), X(6.2), Z(12.3), X(5.1), Z(12.7))
            .C(X(3.9), Z(13.1), X(3.7), Z(14.3), X(4.3), Z(15.0))
            .C(X(5.0), Z(15.8), X(6.5), Z(15.4), X(7.4), Z(15.8))
            .C(X(8.3), Z(16.2), X(8.3), Z(17.2), X(7.5), Z(17.8))
            .C(X(6.5), Z(18.5), X(5.2), Z(18.1), X(4.7), Z(19.0))
            .C(X(4.2), Z(19.9), X(4.4), Z(21.2), X(4.6), Z(22.2))
            .C(X(4.8), Z(23.1), X(4.8), Z(23.7), X(4.5), Z(24.2)), 0.74);
        // 右：乙環鏈（環滿開左）
        抖(p => p.M(X(8.5), Z(5.2))
            .C(X(10.0), Z(5.4), X(11.8), Z(5.9), X(12.7), Z(6.8))
            .C(X(13.7), Z(7.8), X(13.3), Z(8.9), X(12.1), Z(9.0))
            .C(X(11.1), Z(9.1), X(10.7), Z(8.2), X(11.4), Z(7.6)), 0.72);
        抖(p => p.M(X(12.6), Z(9.4))
            .C(X(13.3), Z(10.0), X(13.6), Z(10.6), X(13.4), Z(11.2)), 0.64);
        // 散劃二（短波）
        抖(p => p.M(X(8.7), Z(11.7)).C(X(9.4), Z(12.1), X(10.1), Z(12.3), X(10.7), Z(12.3)), 0.6);
        抖(p => p.M(X(10.9), Z(12.8)).C(X(11.6), Z(13.1), X(12.3), Z(13.2), X(12.8), Z(13.1)), 0.6);
        // 右緣S長曲
        抖(p => p.M(X(13.3), Z(13.6))
            .C(X(12.6), Z(14.7), X(12.6), Z(15.8), X(13.3), Z(16.7))
            .C(X(13.9), Z(17.5), X(13.9), Z(18.4), X(13.4), Z(19.2)), 0.66);
        // 底：雙U大波（下上下，體豐）右出
        抖(p => p.M(X(7.3), Z(19.3))
            .C(X(8.3), Z(18.6), X(9.4), Z(18.5), X(9.9), Z(19.4))
            .C(X(10.4), Z(20.4), X(9.9), Z(21.8), X(10.1), Z(23.0))
            .C(X(10.3), Z(24.2), X(11.1), Z(24.5), X(11.7), Z(23.7))
            .C(X(12.3), Z(22.9), X(12.0), Z(21.5), X(12.3), Z(20.4))
            .C(X(12.6), Z(19.4), X(13.4), Z(19.3), X(13.9), Z(20.1))
            .C(X(14.4), Z(20.9), X(14.3), Z(22.5), X(14.4), Z(24.1)), 0.74);
    });
};
